patch:
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
index c1ce364eb179..f61fb3cbd1a8 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
@@ -1650,6 +1650,25 @@ Instruction *InstCombinerImpl::visitAdd(BinaryOperator &I) {
        match(RHS, m_ZExt(m_NUWSub(m_Value(B), m_Specific(A))))))
     return new ZExtInst(B, LHS->getType());

+  // (X >> C) + zext ((X & ((1 << C) - 1)) != 0) --> (X + ((1 << C) - 1)) >> C
+  const APInt *C;
+  if (match(&I, m_c_Add(m_OneUse(m_LShr(m_Value(A), m_APInt(C))),
+                        m_ZExt(m_OneUse(m_SpecificICmp(ICmpInst::ICMP_NE,
+                                              m_OneUse(m_And(m_Deferred(A), m_Value(B))),
+                                              m_Zero())))))) {
+    unsigned ShiftAmt = C->getZExtValue();
+    if (ShiftAmt > 0 && ShiftAmt < C->getBitWidth()) {
+      APInt Mask = APInt::getLowBitsSet(C->getBitWidth(), ShiftAmt);
+      if (match(B, m_SpecificInt(Mask))) {
+        bool IsNUW = computeOverflowForUnsignedAdd(A, ConstantInt::get(A->getType(), Mask), &I) == OverflowResult::NeverOverflows;
+        if (IsNUW) {
+          Value *Add = Builder.CreateAdd(A, ConstantInt::get(A->getType(), Mask), "", true, I.hasNoSignedWrap());
+          return BinaryOperator::CreateLShr(Add, ConstantInt::get(A->getType(), *C));
+        }
+      }
+    }
+  }
+
   // zext(A) + sext(A) --> 0 if A is i1
   if (match(&I, m_c_BinOp(m_ZExt(m_Value(A)), m_SExt(m_Deferred(A)))) &&
       A->getType()->isIntOrIntVectorTy(1))

